import { motion } from 'framer-motion';
import { FiUpload, FiArrowRight, FiPlay } from 'react-icons/fi';

const Hero = () => {
  return (
    <section className="relative overflow-hidden bg-gradient-to-br from-gray-900 to-purple-900 py-24 md:py-32">
      {/* Background particles */}
      <div className="absolute inset-0 opacity-10">
        {[...Array(30)].map((_, i) => (
          <motion.div
            key={`particle-${i}`}
            className="absolute rounded-full bg-purple-500/30"
            style={{
              width: `${Math.random() * 6 + 2}px`,
              height: `${Math.random() * 6 + 2}px`,
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
            }}
            animate={{
              x: [0, (Math.random() - 0.5) * 40],
              y: [0, (Math.random() - 0.5) * 40],
              opacity: [0.1, 0.8, 0.1],
            }}
            transition={{
              duration: 10 + Math.random() * 20,
              repeat: Infinity,
            }}
          />
        ))}
      </div>

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 grid lg:grid-cols-2 gap-12 items-center">
        {/* Text Content */}
        <div className="text-center lg:text-left">
          <motion.h1
            className="text-4xl md:text-5xl lg:text-6xl font-bold text-white mb-6 leading-tight"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <span className="block">Advanced AI Technology</span>
            <span className="bg-gradient-to-r from-purple-400 to-cyan-300 bg-clip-text text-transparent">
              for the Modern Web
            </span>
          </motion.h1>

          <motion.p
            className="text-lg md:text-xl text-gray-300 mb-10 max-w-lg mx-auto lg:mx-0"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.6 }}
          >
            Harness the power of neural networks and machine learning to transform your digital experience.
          </motion.p>

          <motion.div 
            className="flex flex-col sm:flex-row gap-4 justify-center lg:justify-start"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
          >
            <motion.a
              href="#demo"
              className="flex items-center justify-center gap-2 bg-gradient-to-r from-purple-600 to-blue-500 text-white px-6 py-3 rounded-lg font-medium shadow-lg hover:shadow-xl transition-all group"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.98 }}
            >
              <FiArrowRight className="group-hover:translate-x-1 transition-transform" />
              Get Started
            </motion.a>

            <motion.a
              href="#features"
              className="flex items-center justify-center gap-2 text-white px-6 py-3 rounded-lg font-medium border border-white/20 hover:bg-white/10 transition-colors group"
              whileHover={{ y: -2 }}
            >
              <FiPlay className="text-purple-400 group-hover:text-purple-300" />
              See It In Action
            </motion.a>
          </motion.div>
        </div>

        {/* AI Neural Network Animation */}
        <div className="relative h-80 md:h-96 lg:h-full">
          <div className="absolute inset-0 rounded-2xl overflow-hidden bg-gradient-to-br from-purple-900/20 to-blue-900/10 flex items-center justify-center">
            
            {/* Floating AI Nodes */}
            {[...Array(9)].map((_, i) => {
              const angle = (i * 40) % 360;
              const distance = 30 + (i % 3) * 20;
              const x = 50 + distance * Math.cos(angle * Math.PI / 180);
              const y = 50 + distance * Math.sin(angle * Math.PI / 180);
              
              return (
                <motion.div
                  key={`node-${i}`}
                  className="absolute h-4 w-4 rounded-full bg-gradient-to-br from-purple-400 to-blue-300 shadow-lg"
                  style={{
                    left: `${x}%`,
                    top: `${y}%`,
                  }}
                  animate={{
                    scale: [1, 1.3, 1],
                    opacity: [0.7, 1, 0.7]
                  }}
                  transition={{
                    duration: 2 + Math.random(),
                    repeat: Infinity,
                    delay: i * 0.2
                  }}
                />
              );
            })}

            {/* Central AI Core */}
            <motion.div 
              className="relative z-10 h-24 w-24 rounded-full bg-gradient-to-br from-purple-500 to-blue-400 flex items-center justify-center shadow-xl"
              animate={{
                rotate: 360,
                scale: [1, 1.05, 1]
              }}
              transition={{
                duration: 15,
                repeat: Infinity,
                ease: "linear"
              }}
            >
              <svg 
                className="h-12 w-12 text-white" 
                viewBox="0 0 24 24" 
                fill="none" 
                stroke="currentColor"
              >
                <path 
                  strokeLinecap="round" 
                  strokeLinejoin="round" 
                  strokeWidth={2} 
                  d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2z" 
                />
              </svg>
            </motion.div>

            {/* Neural Connections */}
            <svg className="absolute inset-0 h-full w-full" xmlns="http://www.w3.org/2000/svg">
              {[...Array(9)].map((_, i) => {
                const angle = (i * 40) % 360;
                const distance = 30 + (i % 3) * 20;
                const x1 = 50 + distance * Math.cos(angle * Math.PI / 180);
                const y1 = 50 + distance * Math.sin(angle * Math.PI / 180);
                
                return (
                  <line
                    key={`connection-${i}`}
                    x1="50%"
                    y1="50%"
                    x2={`${x1}%`}
                    y2={`${y1}%`}
                    stroke="rgba(124, 58, 237, 0.3)"
                    strokeWidth="1"
                  />
                );
              })}
            </svg>

            {/* Pulsing Waves */}
            {[...Array(3)].map((_, i) => (
              <motion.div
                key={`wave-${i}`}
                className="absolute border-2 border-purple-400/30 rounded-full"
                style={{
                  width: `${40 + i * 40}%`,
                  height: `${40 + i * 40}%`,
                }}
                animate={{
                  scale: [1, 1.5],
                  opacity: [0.5, 0]
                }}
                transition={{
                  duration: 4 + i,
                  repeat: Infinity,
                  ease: "easeOut"
                }}
              />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
